GUIDescribe = class("GUIDescribe", IGUIWindow)

function GUIDescribe:onLoad()
    self.stText = self:getChildWindowByName("BedWarLicenseGrandDescribe-Text")
end

function GUIDescribe:onDataChange(data)
    local line = math.floor(self.stText:GetFont():GetTextExtent(Lang:getString(data), 1) / 156) + 1
    self.root:SetHeight({ 0, math.max(self.stText:GetFont():GetFontHeight() * line + 44, 96) })
    self.stText:SetText(Lang:getString(data), true)
end